import React, { useState } from "react";
import { FaPlus, FaFolder } from "react-icons/fa";
import { motion } from "framer-motion";

const Sidebar = ({ projects, addProject }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newProject, setNewProject] = useState({ title: "", description: "" });

  // Open/Close Modal
  const toggleModal = () => {
    setIsModalOpen(!isModalOpen);
    setNewProject({ title: "", description: "" }); // Reset input fields when closed
  };

  // Handle Input Change
  const handleChange = (e) => {
    setNewProject({ ...newProject, [e.target.name]: e.target.value });
  };

  // Add Project & Close Modal
  const handleAddProject = () => {
    if (newProject.title.trim() === "") return; // Prevent empty titles
    addProject(newProject); // Send new project to App.js
    toggleModal(); // Close modal
  };

  return (
    <div className="p-4">
      <h2 className="text-lg font-bold">📂 Projects</h2>

      {/* Add Button */}
      <button
        onClick={toggleModal}
        className="mt-3 flex items-center gap-2 bg-blue-500 text-white px-3 py-2 rounded-md hover:bg-blue-600 transition"
      >
        <FaPlus /> Add Project
      </button>

      {/* Project List */}
      <ul className="mt-4">
        {projects.map((project, index) => (
          <li key={index} className="flex items-center gap-2 mt-2">
            <FaFolder className="text-yellow-400" />
            {project.title}
          </li>
        ))}
      </ul>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-50">
          <motion.div
            initial={{ scale: 0.8, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ duration: 0.3, ease: "easeOut" }}
            className="bg-white p-6 rounded-xl shadow-2xl w-96 h-auto flex flex-col"
          >
            <h2 className="text-lg font-bold mb-3">Add New Project</h2>

            {/* Input Fields */}
            <input
              type="text"
              name="title"
              placeholder="Project Title"
              value={newProject.title}
              onChange={handleChange}
              className="border p-2 w-full rounded mb-2"
            />
            <textarea
              name="description"
              placeholder="Project Description"
              value={newProject.description}
              onChange={handleChange}
              className="border p-2 w-full rounded mb-4"
            />

            {/* Buttons */}
            <div className="flex justify-end gap-2">
              <button
                onClick={toggleModal}
                className="bg-gray-500 text-white px-4 py-2 rounded hover:bg-gray-600"
              >
                Cancel
              </button>
              <button
                onClick={handleAddProject}
                className="bg-blue-500 text-white px-4 py-2 rounded hover:bg-blue-600"
              >
                Add
              </button>
            </div>
          </motion.div>
        </div>
      )}
    </div>
  );
};

export default Sidebar;
